function renderWidgetOptions(){let box=$('widgetOptions');if(!box)return;let hidden=data.settings.dashboardHidden||[];box.innerHTML=dashboardOrder().map((id,i)=>`<div class="widget-option"><div><b>${widgetNames[id]}</b><small style="display:block;color:var(--muted)">Position ${i+1}</small></div><label class="switch"><input type="checkbox" ${hidden.includes(id)?'':'checked'} onchange="toggleWidget('${id}',this.checked)"><span class="slider"></span></label></div>`).join('')}
function toggleWidget(id,show){let h=new Set(data.settings.dashboardHidden||[]);show?h.delete(id):h.add(id);data.settings.dashboardHidden=[...h];persist()}
function toggleDashboardCustomise(){$('customisePanel').classList.toggle('open')}
function resetDashboardLayout(){data.settings.dashboardOrder=Object.keys(widgetNames);data.settings.dashboardHidden=[];persist();toast('Dashboard reset')}
function bindDashboardDrag(){let grid=$('dashboardGrid');if(!grid||grid.dataset.bound)return;grid.dataset.bound='1';let dragged=null;grid.addEventListener('dragstart',e=>{let t=e.target.closest('.dashboard-tile');if(!t)return;dragged=t;t.classList.add('dragging')});grid.addEventListener('dragend',()=>{if(dragged)dragged.classList.remove('dragging');dragged=null;data.settings.dashboardOrder=[...grid.querySelectorAll('.dashboard-tile')].map(x=>x.dataset.widget);localStorage.setItem(KEY,JSON.stringify(data));renderWidgetOptions()});grid.addEventListener('dragover',e=>{e.preventDefault();let target=e.target.closest('.dashboard-tile');if(!dragged||!target||target===dragged)return;let r=target.getBoundingClientRect();grid.insertBefore(dragged,(e.clientY-r.top)>r.height/2?target.nextSibling:target)})}
function monthRecords(){let now=new Date(),ym=`${now.getFullYear()}-${pad(now.getMonth()+1)}`;return workdayRecords().filter(r=>r.date.startsWith(ym))}
function renderMonthlyReview(){let rec=monthRecords(),worked=rec.reduce((a,r)=>a+r.work,0),flex=rec.reduce((a,r)=>a+r.flex,0),target=Number(data.settings.targetMinutes||480),good=rec.filter(r=>r.work>=target).length,loc={};rec.forEach(r=>eventsFor(r.date).filter(e=>e.location).forEach(e=>loc[e.location]=(loc[e.location]||0)+1));let top=Object.entries(loc).sort((a,b)=>b[1]-a[1])[0]?.[0]||'No location yet',month=new Date().toLocaleDateString([],{month:'long',year:'numeric'});$('reviewTitle').textContent=`${month} review`;$('monthlyReviewGrid').innerHTML=[['Hours worked',plain(worked)],['Flexi change',fmt(flex)],['Days recorded',rec.length],['Target days',good]].map(x=>`<div class="review-stat"><small>${x[0]}</small><b>${x[1]}</b></div>`).join('');$('monthlyReviewSummary').textContent=rec.length?`You recorded ${rec.length} workday${rec.length===1?'':'s'} this month. Your most-used location was ${top}. ${flex>=0?'You are building flexi overall.':'Your month is currently below target, so the Coach forecast may help you plan the remaining days.'}`:'Complete your first workday this month to generate a monthly review.'}
