function checkAchievements(){let unlocked=milestoneData().filter(x=>x.value>=x.target),seen=new Set(data.settings.seenAchievements||[]),fresh=unlocked.find(x=>!seen.has(x.title));if(!fresh)return;seen.add(fresh.title);data.settings.seenAchievements=[...seen];localStorage.setItem(KEY,JSON.stringify(data));$('achievementTitle').textContent=`${fresh.icon} ${fresh.title}`;$('achievementText').textContent=fresh.text;let pop=$('achievementPop');pop.classList.add('show');setTimeout(()=>pop.classList.remove('show'),4200)}
function renderGoalProgress(){let flexGoal=Number(data.settings.goalFlexiHours||0)*60,dayGoal=Number(data.settings.goalMonthlyDays||0),balance=Math.max(0,runningBalance()),days=monthRecords().length;if($('goalFlexiBar'))$('goalFlexiBar').style.width=(flexGoal?Math.min(100,balance/flexGoal*100):0)+'%';if($('goalDaysBar'))$('goalDaysBar').style.width=(dayGoal?Math.min(100,days/dayGoal*100):0)+'%'}
