let searchFilter='all',plannerYear=new Date().getFullYear();
function coachScore(){let rec=workdayRecords(),score=55;if(rec.length>=5)score+=10;if(rec.length>=15)score+=10;let week=weekDates().reduce((a,x)=>a+flexFor(x,false),0);if(Math.abs(week)<=120)score+=10;let s=currentState();if(['work','location','work_travel'].includes(s))score+=8;if(s==='finished')score+=12;return Math.min(100,score)}
