function editEntry(id){creatingEntry=false;let e=data.events.find(x=>x.id===id);if(!e)return;$('editId').value=id;document.querySelector('#editDialog h2').textContent='Edit entry';$('deleteEntryButton').style.display='';$('saveEntryButton').textContent='Save';$('editType').value=e.type;$('editTime').value=new Date(e.time-new Date(e.time).getTimezoneOffset()*60000).toISOString().slice(0,16);$('editLocation').value=e.location||'';$('editNote').value=e.note||'';$('editCredit').value=e.creditMinutes||'';$('editDialog').showModal()}
function saveEdited(){let id=$('editId').value,t=new Date($('editTime').value).getTime();if(!t)return toast('Choose a valid date and time');let e=creatingEntry?null:data.events.find(x=>x.id===id);if(creatingEntry){e={id:'e'+Date.now()+Math.random().toString(16).slice(2)};data.events.push(e)}if(!e)return;e.type=$('editType').value;e.time=t;e.location=$('editLocation').value.trim();e.note=$('editNote').value.trim();e.creditMinutes=Number($('editCredit').value||0);closeDialog('editDialog');localStorage.setItem(KEY,JSON.stringify(data));render();showDay(dayKey(t));toast(creatingEntry?'Entry added':'Entry updated');creatingEntry=false}
function deleteEdited(){let id=$('editId').value;if(!id||!confirm('Delete this entry?'))return;let d=selectedDay;data.events=data.events.filter(e=>e.id!==id);closeDialog('editDialog');localStorage.setItem(KEY,JSON.stringify(data));render();showDay(d);toast('Entry deleted')}
