// Flexi Buddy 5.5 — favourites and automatic work diary
const favouriteActions={
  wfh:{icon:'🏠',label:'Start WFH',hint:'Home work mode',run:()=>setWorkMode('Home')},
  office:{icon:'🏢',label:'Start office',hint:'Office work mode',run:()=>setWorkMode('Office')},
  visits:{icon:'🚗',label:'Home visits',hint:'Visits work mode',run:()=>setWorkMode('Home Visits')},
  hybrid:{icon:'🔀',label:'Hybrid day',hint:'Mixed locations',run:()=>setWorkMode('Hybrid')},
  quick:{icon:'⚡',label:'Quick work',hint:'Email or messages',run:()=>openQuickWork()},
  travel:{icon:'🛣',label:'Paid travel',hint:'Start or stop',run:()=>toggleTravel()},
  lunch:{icon:'🍽',label:'Lunch',hint:'Start lunch',run:()=>quickAction('lunch')},
  break:{icon:'☕',label:'Paid break',hint:'Start break',run:()=>quickAction('paid_break')},
  meeting:{icon:'👥',label:'Meeting',hint:'Add to timeline',run:()=>quickAction('meeting')},
  note:{icon:'📝',label:'Add note',hint:'Diary note',run:()=>quickAddNote()}
};
function runFavourite(key){let a=favouriteActions[key];if(a)a.run()}
function renderFavourites(){
  if(!$('favouriteGrid'))return;
  let fav=(data.settings.favourites||defaults().settings.favourites).filter(k=>favouriteActions[k]).slice(0,6);
  $('favouriteGrid').innerHTML=fav.map(k=>{let a=favouriteActions[k];return `<button class="favourite-action" onclick="runFavourite('${k}')"><span>${a.icon}</span>${a.label}<small>${a.hint}</small></button>`}).join('');
}
function openFavouriteSettings(){
  let selected=new Set(data.settings.favourites||defaults().settings.favourites);
  $('favouriteSettings').innerHTML=Object.entries(favouriteActions).map(([k,a])=>`<label class="favourite-option"><input type="checkbox" value="${k}" ${selected.has(k)?'checked':''}><span>${a.icon} ${a.label}</span></label>`).join('');
  $('favouriteDialog').showModal();
}
function saveFavouriteSettings(){
  let chosen=[...$('favouriteSettings').querySelectorAll('input:checked')].map(x=>x.value).slice(0,6);
  if(!chosen.length)return alert('Choose at least one favourite.');
  data.settings.favourites=chosen;closeDialog('favouriteDialog');persist();toast('Favourites updated');
}
function eventDiaryLine(e,next){
  let duration=next?Math.max(0,Math.round((next.time-e.time)/60000)):0;
  let at=clock(e.time),loc=e.location?` at ${e.location}`:'';
  if(e.type==='work')return `• Started or resumed work${loc} at ${at}.`;
  if(e.type==='location')return `• Changed work location to ${e.location||'another location'} at ${at}.`;
  if(e.type==='work_travel')return `• Paid work travel started at ${at}${duration?` and lasted ${plain(duration)}`:''}.`;
  if(e.type==='paid_break')return `• Took a paid break at ${at}${duration?` for ${plain(duration)}`:''}.`;
  if(e.type==='lunch')return `• Took lunch at ${at}${duration?` for ${plain(duration)}`:''}.`;
  if(e.type==='pause'||e.type==='unpaid_break')return `• Work paused at ${at}${duration?` for ${plain(duration)}`:''}${e.note?` (${e.note})`:''}.`;
  if(e.type==='quick_work')return `• ${e.note||'Quick work'} — ${plain(Number(e.creditMinutes||0))}.`;
  if(e.type==='credit')return `• Added ${plain(Number(e.creditMinutes||0))} work credit${e.note?` for ${e.note}`:''}.`;
  if(e.type==='note')return `• ${e.note||'Note added'}.`;
  if(e.type==='finish')return `• Finished work at ${at}.`;
  return e.note?`• ${e.note}.`:'';
}
function generatedDiary(d=dayKey(Date.now())){
  let ev=eventsFor(d),sp=special(d),dateLabel=new Date(d+'T12:00').toLocaleDateString([],{weekday:'long',day:'numeric',month:'long',year:'numeric'});
  if(sp)return `${dateLabel}\n\n${({annual_leave:'Annual leave',flexi_day:'Flexi day',part_flexi:'Part flexi leave',sick:'Sick leave',dependants:'Dependants leave',special:'Special leave',part_year:'Part-year day',bank_holiday:'Bank holiday'}[sp.type]||'Leave')} recorded${sp.hours?` (${sp.hours} hours)`:''}.`;
  if(!ev.length)return `${dateLabel}\n\nNo work activity has been recorded yet.`;
  let c=calc(d,d===dayKey(Date.now())&&!hasFinished(d)),lines=ev.map((e,i)=>eventDiaryLine(e,ev[i+1])).filter(Boolean),flex=flexFor(d,d===dayKey(Date.now())&&!hasFinished(d));
  let status=hasFinished(d)?`Worked ${plain(c.work+c.credit)} in total and finished with ${fmt(flex)} flexi.`:`So far, ${plain(c.work+c.credit)} has been recorded with ${fmt(flex)} projected flexi.`;
  return `${dateLabel}\n\n${lines.join('\n')}\n\n${status}`;
}
function currentDiary(){let d=dayKey(Date.now());return (data.settings.diaryEdits||{})[d]||generatedDiary(d)}
function renderDiary(){if(!$('diaryText'))return;let text=currentDiary();$('diaryText').textContent=text;$('diaryText').classList.toggle('diary-empty',eventsFor(dayKey(Date.now())).length===0)}
function editDiary(){$('diaryEditor').value=currentDiary();$('diaryDialog').showModal()}
function saveDiaryEdit(){let d=dayKey(Date.now());data.settings.diaryEdits=data.settings.diaryEdits||{};data.settings.diaryEdits[d]=$('diaryEditor').value.trim();closeDialog('diaryDialog');persist();toast('Diary wording saved')}
async function copyDiary(){try{await navigator.clipboard.writeText(currentDiary());toast('Diary copied')}catch(e){let t=document.createElement('textarea');t.value=currentDiary();document.body.appendChild(t);t.select();document.execCommand('copy');t.remove();toast('Diary copied')}}
function downloadDiary(){let d=dayKey(Date.now());download(`flexi-buddy-diary-${d}.txt`,currentDiary(),'text/plain')}
